diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..1ab4563e9695 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2263,6 +2263,17 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     return CallInst::Create(F, {Op0, Z});
   }

+  // sub(smin(X +nsw/nuw 1, Y), smin(X, Y)) --> zext/sext (X <s Y)
+  // The add cannot overflow, so the difference is either 0 or 1.
+  Value *One;
+  if (MinMax->isSigned() &&
+      match(Op0, m_SMin(m_OneUse(m_NUWAdd(m_Specific(X), m_One())),
+                        m_Specific(Y)))) {
+    Value *Cmp = Builder.CreateICmpSLT(X, Y);
+    return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                              ConstantInt::getNullValue(Ty));
+  }
+
   return nullptr;
 }

diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 33b66aeaffe6..2e89824a2edd 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -1240,6 +1240,10 @@ static Instruction *foldClampRangeOfTwo(IntrinsicInst *II,
   Value *I0 = II->getArgOperand(0), *I1 = II->getArgOperand(1);
   Value *X;
   const APInt *C0, *C1;
+  // Canonicalize by preferring a constant RHS for scalar ops.
+  if (II->getType()->isIntOrIntVectorTy() && II->getType()->isIntegerTy() &&
+      !isa<ConstantInt>(I1))
+    std::swap(I0, I1);
   if (!match(I1, m_APInt(C1)) || !I0->hasOneUse())
     return nullptr;

